    @Test
    @DisplayName("setTrackErrors(0) disables error tracking branch and isTrackErrors returns false")
    public void test_TC01() {
        // GIVEN: a fresh HTML parser with default error tracking disabled
        Parser parser = Parser.htmlParser();
        // WHEN: disabling error tracking by setting maxErrors to 0 (hits branch B1(false)→B2)
        parser.setTrackErrors(0);
